import React, { useState, useEffect } from "react";
import { ShoppingCart, MessageCircle, Star } from "lucide-react";
import { Link, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { useCart } from "@/frontend/contexts/CartContext";
import { useAuth } from "@/frontend/contexts/AuthContext";
import { useChatContext } from "@/frontend/contexts/ChatContext";
import { toast } from "sonner";
import { db } from "@/backend/config/firebase";
import { ref as dbRef, onValue } from "firebase/database";
import { formatPrice, getValidImageUrl } from "@/lib/utils";
import { sendMessage, getChatRoomId } from "@/backend/services/chatService";

export interface RTDBProduct {
  id: string;
  sellerUid?: string;
  name: string;
  price: number;
  description: string;
  images: string[];
  aiEligibilityScore: string;
  createdAt: any;
}



export default function ProductCard({ product, index = 0 }: { product: RTDBProduct; index?: number }) {
  const { addToCart } = useCart();
  const { currentUser, role } = useAuth();
  const { openChat } = useChatContext();
  const navigate = useNavigate();
  const [ratingData, setRatingData] = useState({ average: 0, count: 0 });

  useEffect(() => {
    const reviewsRef = dbRef(db, `reviews/${product.id}`);
    const unsubscribe = onValue(reviewsRef, (snapshot) => {
      if (snapshot.exists()) {
        const data = snapshot.val();
        const reviewsArray = Object.values(data) as { rating: number }[];
        const avg = reviewsArray.reduce((acc, rev) => acc + rev.rating, 0) / reviewsArray.length;
        setRatingData({ average: Number(avg.toFixed(1)), count: reviewsArray.length });
      } else {
        setRatingData({ average: 0, count: 0 });
      }
    });
    return () => unsubscribe();
  }, [product.id]);

  const imageUrl = getValidImageUrl(product);
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, delay: index * 0.1 }}
      whileHover={{ scale: 1.03 }}
      className="h-full"
    >
      <Link to={`/product/${product.id}`} className="group block h-full">
        <div className="bg-card rounded-2xl p-4 shadow-sm hover:shadow-xl transition-all duration-300 border-none h-full flex flex-col">
          <div className="aspect-square rounded-xl overflow-hidden relative bg-muted/30 mb-4">
            <motion.img
              whileHover={{ scale: 1.05 }}
              transition={{ duration: 0.6, ease: "easeOut" }}
              src={imageUrl}
              alt={product.name}
              onError={(e) => { e.currentTarget.src = "https://fakeimg.pl/300x300?text=No+Image"; }}
              className="w-full h-full object-cover"
            />
            {/* Grade Badge */}
            <div className="absolute top-2 left-2 bg-primary text-primary-foreground text-[10px] font-bold px-2.5 py-0.5 rounded-full uppercase tracking-wider shadow-sm">
              Grade A
            </div>
          </div>

          <div className="flex flex-col flex-1">
            <h3 className="font-semibold text-foreground text-sm line-clamp-2 mb-1 group-hover:text-primary transition-colors">
              {product.name}
            </h3>

            <div className="flex items-center gap-1.5 mb-2">
              <Star className="w-3.5 h-3.5 fill-primary text-primary" />
              <span className="text-xs font-bold text-foreground">{ratingData.average > 0 ? ratingData.average : "4.8"}</span>
              <span className="text-xs text-muted-foreground">({ratingData.count > 0 ? ratingData.count : "12"})</span>
            </div>

            <div className="flex items-center justify-between flex-1">
              <span className="font-bold text-primary text-base">{formatPrice(product.price)}</span>
            </div>

            <div className="mt-4 pt-2">
              <button
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();

                  if (!currentUser) {
                    toast.error("Akses Ditolak", { description: "Silakan login terlebih dahulu untuk mulai berbelanja." });
                    navigate("/login");
                    return;
                  }

                  if (role === "Penjual") {
                    toast.error("Akses Ditolak", { description: "Akun Penjual tidak dapat melakukan chat/pembelian." });
                    return;
                  }

                  const sellerId = product.sellerUid || "unknown_seller";
                  openChat(currentUser.uid, sellerId, product.id, product.name, imageUrl, product.price);

                  // Optional: kita bisa mengirimkan pesan otomatis di sini menggunakan sendMessage dari chatService
                  // Namun, di ChatModal kita bisa menghandlenya atau biarkan pembeli mengetik sendiri.
                  // Sesuai permintaan: otomatis menyisipkan pesan pembuka
                  const roomId = getChatRoomId(currentUser.uid, sellerId, product.id);
                  sendMessage(roomId, currentUser.uid, currentUser.displayName || "Pembeli", `Halo, apakah ${product.name} masih tersedia?`);
                }}
                className="w-full py-2.5 bg-[#A67B5B] text-white text-sm font-medium rounded-lg hover:bg-[#8B6547] hover:shadow-[0_0_15px_rgba(166,123,91,0.5)] transition-all duration-300 flex items-center justify-center shadow-sm"
              >
                Tanya Sekarang
              </button>
            </div>
          </div>
        </div>
      </Link>
    </motion.div>
  );
}

import React, { useState } from "react";
import { verifyBeforeUpdateEmail } from "firebase/auth";
import { toast } from "sonner";
import { Loader2, Mail, AlertCircle, CheckCircle2 } from "lucide-react";
import { useAuth } from "@/frontend/contexts/AuthContext";

interface UpdateEmailFormProps {
  currentEmail: string;
}

export default function UpdateEmailForm({ currentEmail }: UpdateEmailFormProps) {
  const { currentUser } = useAuth();
  const [newEmail, setNewEmail] = useState("");
  const [isUpdating, setIsUpdating] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");

  if (!currentUser) return null;

  const handleUpdateEmail = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEmail.trim() || newEmail === currentEmail) return;

    setIsUpdating(true);
    setSuccessMessage("");

    try {
      await verifyBeforeUpdateEmail(currentUser, newEmail);
      setSuccessMessage("Tautan verifikasi telah dikirim ke email baru Anda. Silakan cek kotak masuk Anda.");
      toast.success("Verifikasi email terkirim", {
        description: "Silakan cek kotak masuk pada email baru Anda.",
      });
      setNewEmail(""); // Reset input
    } catch (error: any) {
      console.error("Gagal memperbarui email:", error);

      switch (error.code) {
        case "auth/requires-recent-login":
          toast.error("Sesi Berakhir", {
            description: "Sesi Anda sudah terlalu lama demi keamanan. Silakan logout dan login kembali sebelum mengubah alamat email.",
            duration: 6000,
          });
          break;
        case "auth/email-already-in-use":
          toast.error("Gagal", {
            description: "Alamat email ini sudah digunakan oleh akun lain.",
          });
          break;
        case "auth/invalid-email":
          toast.error("Gagal", {
            description: "Format alamat email tidak valid.",
          });
          break;
        default:
          toast.error("Terjadi Kesalahan", {
            description: error.message || "Gagal mengirimkan tautan verifikasi email.",
          });
          break;
      }
    } finally {
      setIsUpdating(false);
    }
  };

  return (
    <div className="space-y-4 pt-4 border-t border-border mt-4">
      <div className="flex items-start justify-between">
        <div>
          <h3 className="font-bold text-lg">Pembaruan Email</h3>
          <p className="text-sm text-muted-foreground mt-1">
            Email saat ini: <span className="font-medium text-foreground">{currentEmail}</span>
          </p>
        </div>
      </div>

      <form onSubmit={handleUpdateEmail} className="space-y-4 max-w-md">
        <div className="space-y-2">
          <label htmlFor="newEmail" className="text-sm font-medium text-foreground flex items-center gap-2">
            <Mail className="w-4 h-4 text-muted-foreground" />
            Alamat Email Baru
          </label>
          <div className="flex gap-3">
            <input
              id="newEmail"
              type="email"
              value={newEmail}
              onChange={(e) => setNewEmail(e.target.value)}
              placeholder="Masukkan email baru..."
              disabled={isUpdating}
              className="flex-1 px-4 py-2.5 rounded-lg border border-border bg-background outline-none focus:ring-2 focus:ring-primary transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              required
            />
            <button
              type="submit"
              disabled={isUpdating || !newEmail.trim() || newEmail === currentEmail}
              className="bg-primary text-primary-foreground px-5 py-2.5 rounded-lg font-medium hover:opacity-90 transition-opacity flex items-center justify-center gap-2 disabled:opacity-50 min-w-[140px]"
            >
              {isUpdating ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Memproses
                </>
              ) : (
                "Simpan Email"
              )}
            </button>
          </div>
        </div>

        {successMessage && (
          <div className="bg-green-50 dark:bg-green-950/30 border border-green-200 dark:border-green-900/50 rounded-lg p-4 flex items-start gap-3 mt-4">
            <CheckCircle2 className="w-5 h-5 text-green-600 dark:text-green-500 shrink-0 mt-0.5" />
            <p className="text-sm text-green-800 dark:text-green-300">
              {successMessage}
            </p>
          </div>
        )}
      </form>
    </div>
  );
}

import React, { useState } from "react";
import { updatePassword } from "firebase/auth";
import { toast } from "sonner";
import { Loader2, KeyRound } from "lucide-react";
import { useAuth } from "@/frontend/contexts/AuthContext";

export default function UpdatePasswordForm() {
  const { currentUser } = useAuth();
  const [newPassword, setNewPassword] = useState("");
  const [isUpdating, setIsUpdating] = useState(false);

  if (!currentUser) return null;

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPassword || newPassword.length < 6) {
      toast.error("Password terlalu pendek", { description: "Password harus terdiri dari minimal 6 karakter." });
      return;
    }

    setIsUpdating(true);

    try {
      await updatePassword(currentUser, newPassword);
      toast.success("Berhasil!", {
        description: "Password akun Anda telah berhasil diubah.",
      });
      setNewPassword(""); // Reset input
    } catch (error: any) {
      console.error("Gagal memperbarui password:", error);

      switch (error.code) {
        case "auth/requires-recent-login":
          toast.error("Sesi Berakhir", {
            description: "Sesi Anda sudah terlalu lama demi keamanan. Silakan logout dan login kembali sebelum mengubah password.",
            duration: 6000,
          });
          break;
        case "auth/weak-password":
          toast.error("Password Lemah", {
            description: "Silakan gunakan kombinasi password yang lebih kuat.",
          });
          break;
        default:
          toast.error("Terjadi Kesalahan", {
            description: error.message || "Gagal mengubah password.",
          });
          break;
      }
    } finally {
      setIsUpdating(false);
    }
  };

  return (
    <div className="space-y-4 pt-4 border-t border-border mt-4">
      <div className="flex items-start justify-between">
        <div>
          <h3 className="font-bold text-lg">Pembaruan Password</h3>
          <p className="text-sm text-muted-foreground mt-1">
            Gunakan password yang kuat dengan kombinasi huruf dan angka.
          </p>
        </div>
      </div>

      <form onSubmit={handleUpdatePassword} className="space-y-4 max-w-md">
        <div className="space-y-2">
          <label htmlFor="newPassword" className="text-sm font-medium text-foreground flex items-center gap-2">
            <KeyRound className="w-4 h-4 text-muted-foreground" />
            Password Baru
          </label>
          <div className="flex gap-3">
            <input
              id="newPassword"
              type="password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              placeholder="Minimal 6 karakter..."
              disabled={isUpdating}
              className="flex-1 px-4 py-2.5 rounded-lg border border-border bg-background outline-none focus:ring-2 focus:ring-primary transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              required
              minLength={6}
            />
            <button
              type="submit"
              disabled={isUpdating || newPassword.length < 6}
              className="bg-primary text-primary-foreground px-5 py-2.5 rounded-lg font-medium hover:opacity-90 transition-opacity flex items-center justify-center gap-2 disabled:opacity-50 min-w-[140px]"
            >
              {isUpdating ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Menyimpan
                </>
              ) : (
                "Ubah Password"
              )}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { UploadCloud, Scan, Tag, TrendingUp, CheckCircle, Sparkles, X, Image as ImageIcon } from 'lucide-react';

export default function AIProductFeasibility() {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [status, setStatus] = useState<"idle" | "analyzing" | "completed">("idle");
  const [loadingText, setLoadingText] = useState("");

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0];
    if (selected) {
      setFile(selected);
      setPreview(URL.createObjectURL(selected));
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const dropped = e.dataTransfer.files?.[0];
    if (dropped) {
      setFile(dropped);
      setPreview(URL.createObjectURL(dropped));
    }
  };

  const startAnalysis = () => {
    setStatus("analyzing");
    setLoadingText("Menganalisis serat kain...");

    setTimeout(() => {
      setLoadingText("Mencocokkan merek dengan database tren...");
    }, 1000);

    setTimeout(() => {
      setLoadingText("Menghitung estimasi harga pasar...");
    }, 2000);

    setTimeout(() => {
      setStatus("completed");
    }, 3000);
  };

  const reset = () => {
    setFile(null);
    setPreview(null);
    setStatus("idle");
  };

  return (
    <div className="w-full max-w-2xl bg-card border border-border rounded-xl shadow-sm p-6 sm:p-8">
      <div className="flex items-center gap-2 mb-6">
        <Sparkles className="w-6 h-6 text-primary" />
        <h2 className="text-xl font-bold text-foreground">AI Kelayakan Barang</h2>
      </div>

      <AnimatePresence mode="wait">
        {status === "idle" && (
          <motion.div
            key="idle"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            {!preview ? (
              <div 
                onDragOver={(e) => e.preventDefault()}
                onDrop={handleDrop}
                className="border-2 border-dashed border-border rounded-xl p-10 flex flex-col items-center justify-center text-center bg-secondary/30 hover:bg-secondary/50 transition-colors cursor-pointer relative"
              >
                <input 
                  type="file" 
                  accept="image/*" 
                  onChange={handleFileChange} 
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                <div className="w-16 h-16 bg-background rounded-full flex items-center justify-center shadow-sm mb-4 border border-border">
                  <UploadCloud className="w-8 h-8 text-primary" />
                </div>
                <h3 className="font-semibold text-foreground mb-1">Unggah Foto Barang</h3>
                <p className="text-sm text-muted-foreground max-w-xs">
                  Drag & drop foto atau klik untuk memilih file dari perangkat Anda
                </p>
              </div>
            ) : (
              <div className="border border-border rounded-xl p-4 bg-background">
                <div className="relative w-full aspect-video rounded-lg overflow-hidden bg-secondary mb-4 border border-border">
                  <img src={preview} alt="Preview" className="w-full h-full object-contain" />
                  <button 
                    onClick={reset}
                    className="absolute top-2 right-2 p-1.5 bg-black/50 hover:bg-black/70 text-white rounded-full backdrop-blur-sm transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
                <button
                  onClick={startAnalysis}
                  className="w-full py-3 bg-primary text-primary-foreground font-medium rounded-lg hover:opacity-90 transition-opacity flex items-center justify-center gap-2"
                >
                  <Scan className="w-5 h-5" />
                  Analisis dengan AI
                </button>
              </div>
            )}
          </motion.div>
        )}

        {status === "analyzing" && (
          <motion.div
            key="analyzing"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            className="flex flex-col items-center justify-center py-12 text-center"
          >
            <div className="relative w-24 h-24 mb-6">
              <div className="absolute inset-0 border-4 border-primary/20 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-primary rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center text-primary">
                <Sparkles className="w-8 h-8 animate-pulse" />
              </div>
            </div>
            <h3 className="font-bold text-lg text-foreground mb-2">AI Sedang Bekerja</h3>
            <p className="text-sm text-muted-foreground animate-pulse">{loadingText}</p>
          </motion.div>
        )}

        {status === "completed" && (
          <motion.div
            key="completed"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-6"
          >
            <div className="bg-gradient-to-br from-green-50 to-emerald-50 dark:from-green-950/20 dark:to-emerald-900/10 border border-green-200 dark:border-green-900/50 rounded-xl p-6 flex items-center justify-between shadow-sm">
              <div>
                <p className="text-sm font-medium text-green-700 dark:text-green-400 mb-1">Skor Kelayakan Jual</p>
                <div className="flex items-end gap-2">
                  <span className="text-4xl font-black text-green-600 dark:text-green-500">85%</span>
                  <span className="text-sm font-medium text-green-700 dark:text-green-400 mb-1.5">/ Sangat Layak</span>
                </div>
              </div>
              <div className="w-16 h-16 rounded-full bg-green-100 dark:bg-green-900/40 flex items-center justify-center text-green-600 dark:text-green-500 border border-green-200 dark:border-green-800 shadow-inner">
                <CheckCircle className="w-8 h-8" />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="bg-background border border-border rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-2 text-foreground">
                  <ImageIcon className="w-4 h-4 text-primary" />
                  <h4 className="font-semibold text-sm">Kondisi Fisik</h4>
                </div>
                <p className="text-sm text-muted-foreground">Warna memudar 10% di kerah, tidak ada robekan.</p>
              </div>

              <div className="bg-background border border-border rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-2 text-foreground">
                  <Tag className="w-4 h-4 text-primary" />
                  <h4 className="font-semibold text-sm">Merek &amp; Kategori</h4>
                </div>
                <p className="text-sm text-muted-foreground">Terdeteksi: Levi's Denim Vintage.</p>
              </div>

              <div className="bg-background border border-border rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-2 text-foreground">
                  <TrendingUp className="w-4 h-4 text-primary" />
                  <h4 className="font-semibold text-sm">Tren Pasar</h4>
                </div>
                <p className="text-sm text-muted-foreground">Permintaan Tinggi: Gaya Y2K sedang naik daun.</p>
              </div>

              <div className="bg-primary/5 border border-primary/20 rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-2 text-primary">
                  <Sparkles className="w-4 h-4" />
                  <h4 className="font-semibold text-sm">Rekomendasi Harga</h4>
                </div>
                <p className="text-lg font-bold text-foreground">Rp 150.000 - Rp 220.000</p>
              </div>
            </div>

            <button
              onClick={reset}
              className="w-full py-2.5 bg-secondary text-secondary-foreground font-medium rounded-lg hover:bg-secondary/80 transition-colors"
            >
              Analisis Barang Lain
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useRef, useMemo, useEffect } from "react";
import { MapContainer, TileLayer, Marker, Polyline, useMapEvents, useMap } from "react-leaflet";
import L, { LatLngExpression } from "leaflet";
import { X, MapPin, Loader2, Search } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { toast } from "sonner";

// Fix Leaflet's default icon issue in React
delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png",
  iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png",
});

interface MapModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelectLocation: (address: string, city: string, province: string, lat: number, lng: number) => void;
  sellerLocations?: { lat: number; lng: number }[];
}

// Komponen tambahan untuk update center peta secara terprogram
function MapUpdater({ center }: { center: L.LatLng }) {
  const map = useMap();
  useEffect(() => {
    map.setView(center, map.getZoom(), { animate: true });
  }, [center, map]);
  return null;
}

export default function MapModal({ isOpen, onClose, onSelectLocation, sellerLocations = [] }: MapModalProps) {
  const [position, setPosition] = useState<L.LatLng>(new L.LatLng(-6.2088, 106.8456)); // Jakarta default
  const [isLoading, setIsLoading] = useState(false);
  const [addressData, setAddressData] = useState<{ address: string; city: string; province: string } | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);

  const markerRef = useRef<L.Marker>(null);
  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Initialize Map
  useEffect(() => {
    if (isOpen) {
      // Small delay to allow map layout to settle
      setTimeout(() => {
        window.dispatchEvent(new Event('resize'));
      }, 100);

      // Auto fetch location for default position if empty
      if (!addressData) {
        fetchAddress(position.lat, position.lng);
      }
    }
  }, [isOpen]);

  // Reverse Geocoding using Nominatim
  const fetchAddress = async (lat: number, lng: number) => {
    setIsLoading(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`);
      if (!response.ok) throw new Error("Gagal mengambil alamat");
      const data = await response.json();

      const city = data.address.city || data.address.town || data.address.village || data.address.county || "";
      const province = data.address.state || data.address.region || "";
      const fullAddress = data.display_name || "";

      setAddressData({ address: fullAddress, city, province });
    } catch (error) {
      console.error(error);
      toast.error("Gagal mendapatkan nama jalan", { description: "Pastikan koneksi internet stabil." });
    } finally {
      setIsLoading(false);
    }
  };

  // Click map to set marker
  const MapEvents = () => {
    useMapEvents({
      click(e) {
        setPosition(e.latlng);
        fetchAddress(e.latlng.lat, e.latlng.lng);
      },
    });
    return null;
  };

  // Debounced Search Function
  const handleSearch = (query: string) => {
    setSearchQuery(query);
    if (!query) return;

    if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);

    searchTimeoutRef.current = setTimeout(async () => {
      setIsSearching(true);
      try {
        const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&countrycodes=id&limit=1`);
        if (!res.ok) throw new Error("Search API failed");
        const data = await res.json();

        if (data && data.length > 0) {
          const lat = parseFloat(data[0].lat);
          const lon = parseFloat(data[0].lon);
          const newPos = new L.LatLng(lat, lon);
          setPosition(newPos);
          fetchAddress(lat, lon);
        } else {
          toast.error("Lokasi tidak ditemukan", { description: "Coba gunakan nama jalan atau kota yang lebih spesifik." });
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
      }
    }, 800); // 800ms debounce
  };

  const eventHandlers = useMemo(
    () => ({
      dragend() {
        const marker = markerRef.current;
        if (marker != null) {
          const latlng = marker.getLatLng();
          setPosition(latlng);
          fetchAddress(latlng.lat, latlng.lng);
        }
      },
    }),
    [],
  );

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <motion.div 
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="w-full max-w-2xl bg-card rounded-2xl shadow-2xl overflow-hidden flex flex-col"
          >
            <div className="p-4 border-b border-border flex justify-between items-center bg-secondary/50">
              <h2 className="font-bold text-foreground text-lg flex items-center gap-2">
                <MapPin className="w-5 h-5 text-primary" /> Pilih Lokasi Pengiriman
              </h2>
              <button onClick={onClose} className="p-2 text-muted-foreground hover:bg-secondary rounded-full transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4 border-b border-border bg-secondary/30 relative">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <input
                  type="text"
                  placeholder="Cari jalan, kecamatan, atau kota..."
                  value={searchQuery}
                  onChange={(e) => handleSearch(e.target.value)}
                  className="w-full pl-9 pr-4 py-2 rounded-lg border border-border bg-background focus:ring-2 focus:ring-primary outline-none text-sm"
                />
                {isSearching && <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-primary" />}
              </div>
            </div>

            <div className="relative h-[400px] w-full bg-muted z-0">
              <MapContainer 
                center={position} 
                zoom={13} 
                scrollWheelZoom={true} 
                className="h-full w-full z-0"
                maxBounds={[[-11.0, 95.0], [6.0, 141.0]]} // Geofencing Indonesia
                minZoom={5}
              >
                <MapUpdater center={position} />
                <TileLayer
                  attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />

                {/* Visualisasi Rute dari Semua Penjual ke Titik Pembeli */}
                {sellerLocations.map((seller, idx) => (
                  <Polyline 
                    key={idx} 
                    positions={[[seller.lat, seller.lng], [position.lat, position.lng]]} 
                    pathOptions={{ color: '#A67B5B', weight: 3, dashArray: '5, 10', opacity: 0.7 }}
                  />
                ))}

                <Marker 
                  draggable={true}
                  eventHandlers={eventHandlers}
                  position={position}
                  ref={markerRef}
                />
                <MapEvents />
              </MapContainer>
            </div>

            <div className="p-5 border-t border-border bg-card">
              <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-2">Alamat Terpilih</p>
              <div className="bg-secondary/30 border border-border p-3 rounded-lg min-h-[60px] flex items-center">
                {isLoading ? (
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Loader2 className="w-4 h-4 animate-spin" /> Sedang memuat alamat...
                  </div>
                ) : addressData ? (
                  <div>
                    <p className="text-sm font-medium text-foreground line-clamp-2">{addressData.address}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-[11px] bg-primary/10 text-primary font-bold px-2 py-0.5 rounded-full">{addressData.city || "Kota Tidak Diketahui"}</span>
                      <span className="text-[11px] bg-secondary text-secondary-foreground font-bold px-2 py-0.5 rounded-full">{addressData.province || "Provinsi Tidak Diketahui"}</span>
                    </div>
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground">Geser pin peta untuk memilih alamat secara otomatis.</p>
                )}
              </div>

              <div className="flex gap-3 mt-5">
                <button 
                  onClick={onClose}
                  className="px-4 py-2 border border-border text-foreground text-sm font-medium rounded-lg hover:bg-secondary transition-colors"
                >
                  Batal
                </button>
                <button 
                  onClick={() => {
                    if (addressData) {
                      onSelectLocation(addressData.address, addressData.city, addressData.province, position.lat, position.lng);
                      onClose();
                    } else {
                      toast.error("Pilih lokasi terlebih dahulu di peta");
                    }
                  }}
                  disabled={isLoading || !addressData}
                  className="flex-1 px-4 py-2 bg-primary text-primary-foreground text-sm font-bold rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50"
                >
                  Gunakan Lokasi Ini
                </button>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

