  activeChatRoomId: string | null;
  activeUserAId: string | null;
  activeUserAName: string | null;
  activeUserBId: string | null;
  activeUserBName: string | null;
  openChat: (
    userAId: string,
    userAName: string,
    userBId: string,
    userBName: string
  ) => void;
  closeChat: () => void;
  toggleChat: () => void;
}

const ChatContext = createContext<ChatContextType>({
  isChatOpen: false,
  activeChatRoomId: null,
  activeUserAId: null,
  activeUserAName: null,
  activeUserBId: null,
  activeUserBName: null,
  openChat: () => {},
  closeChat: () => {},
  toggleChat: () => {},
});

export const useChatContext = () => useContext(ChatContext);

export const ChatProvider = ({ children }: { children: React.ReactNode }) => {
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [activeUserAId, setActiveUserAId] = useState<string | null>(null);
  const [activeUserAName, setActiveUserAName] = useState<string | null>(null);
  const [activeUserBId, setActiveUserBId] = useState<string | null>(null);
  const [activeUserBName, setActiveUserBName] = useState<string | null>(null);

  const openChat = (
    userAId: string,
    userAName: string,
    userBId: string,
    userBName: string
  ) => {
