import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import Navbar from "@/frontend/components/layout/Navbar";
import { auth, googleProvider, facebookProvider, db } from "@/backend/config/firebase";
import { signInWithEmailAndPassword, signInWithPopup, User } from "firebase/auth";
import { ref, get, child, set, query, orderByChild, equalTo, remove } from "firebase/database";
import { toast } from "sonner";
import { useAuth } from "@/frontend/contexts/AuthContext";
import { translateAuthError, SYSTEM_MASTER_PASSWORD } from "@/lib/utils";

export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [loginMethod, setLoginMethod] = useState<"email" | "phone">("email");
  const [phone, setPhone] = useState("");
  const [phonePassword, setPhonePassword] = useState("");
  const [otp, setOtp] = useState("");
  const [showOtpInput, setShowOtpInput] = useState(false);
  const [countdown, setCountdown] = useState(0);

  const [showRoleModal, setShowRoleModal] = useState(false);
  const [pendingUser, setPendingUser] = useState<User | null>(null);

  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (countdown > 0) {
      timer = setTimeout(() => setCountdown(countdown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [countdown]);

  const navigate = useNavigate();
  const { role } = useAuth(); 

  const redirectUser = (userRole: string) => {
    if (userRole === "Penjual") {
      navigate("/seller/upload");
    } else {
      navigate("/");
    }
  };

  const handleSocialLogin = async (provider: any) => {
    setIsLoading(true);
    try {
      const result = await signInWithPopup(auth, provider);
      const user = result.user;

      const dbRef = ref(db);
      const snapshot = await get(child(dbRef, `users/${user.uid}`));

      if (!snapshot.exists()) {
        setPendingUser(user);
        setShowRoleModal(true);
        setIsLoading(false);
        return;
      } else {
        const userData = snapshot.val();
        const userRole = userData.role || "Pembeli";
        toast.success("Berhasil masuk!");
        redirectUser(userRole);
      }
    } catch (error: any) {
      console.error("[LOGIN] Social Login Error:", error);
      toast.error("Gagal masuk", { description: translateAuthError(error) });
      setIsLoading(false);
    }
  };

  const handleRoleSelection = async (selectedRole: string) => {
    if (!pendingUser) return;
    setIsLoading(true);
    setShowRoleModal(false);
    try {
      await set(ref(db, `users/${pendingUser.uid}`), {
        uid: pendingUser.uid,
        name: pendingUser.displayName || "Pengguna",
        email: pendingUser.email || "",
        phone: pendingUser.phoneNumber || "",
        role: selectedRole,
        createdAt: new Date().toISOString(),
      });
      toast.success("Berhasil masuk!");
      redirectUser(selectedRole);
    } catch (error: any) {
      console.error("[LOGIN] Role Selection Error:", error);
      toast.error("Gagal menyimpan role", { description: translateAuthError(error) });
    } finally {
      setIsLoading(false);
      setPendingUser(null);
    }
  };

  // --- CUSTOM OTP ENGINE ---
  const sendOTPViaProvider = async (phone: string, otpCode: string) => {
    const actionText = "masuk ke akun";
    const message = `*🔐 VERIFIKASI KEAMANAN SALIN GAYA 🔐*

Halo,
Berikut adalah kode OTP rahasia Anda untuk ${actionText} Salin Gaya:

*${otpCode}*

⚠️ *PERHATIAN:*
Jangan pernah memberikan kode ini kepada siapa pun, *termasuk* pihak Salin Gaya. Demi keamanan, kode ini hanya berlaku selama 5 menit.

Jika Anda tidak merasa melakukan aktivitas ini, mohon abaikan pesan ini.

Terima kasih,
*Tim Salin Gaya* 🛍️`;

    try {
      const response = await fetch('https://api.fonnte.com/send', {
        method: 'POST',
        headers: {
          'Authorization': import.meta.env.VITE_FONNTE_TOKEN,
        },
        body: new URLSearchParams({
          target: String(phone),
          message: message,
        })
      });

      const data = await response.json();
      if (data.status) {
        toast.success("OTP berhasil dikirim ke WhatsApp!");
        return true;
      } else {
        const errorReason = data.reason || data.detail || "Gagal mengirim via API.";
        toast.error(`Gagal mengirim WA: ${errorReason}`);
        return false;
      }
    } catch (error: any) {
      toast.error("Gagal terhubung ke server WhatsApp", { description: error.message });
      return false;
    }
  };

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!phone || !phonePassword) {
      toast.error("Masukkan nomor HP dan password yang valid");
      return;
    }
    setIsLoading(true);
    try {
      const formattedPhone = phone.startsWith('0') ? `+62${phone.slice(1)}` : (phone.startsWith('+') ? phone : `+62${phone}`);
      const cleanPhone = formattedPhone.replace(/\+/g, '');

      // Tahap 1: Validasi Lokal via RTDB
      const usersRef = ref(db, 'users');
      const phoneQuery = query(usersRef, orderByChild('phone'), equalTo(formattedPhone));
      const userSnapshotQuery = await get(phoneQuery);

      if (!userSnapshotQuery.exists()) {
        toast.error("Nomor belum terdaftar", { description: "Silakan Registrasi terlebih dahulu!" });
        setIsLoading(false);
        return;
      }

      const userData = Object.values(userSnapshotQuery.val())[0] as any;
      if (userData.originalPassword !== phonePassword) {
        toast.error("Nomor HP atau Password salah");
        setIsLoading(false);
        return;
      }

      // Validasi sukses, buat session dengan Firebase Auth menggunakan Master Password
      const ghostEmail = `${cleanPhone}@salingaya.com`;
      try {
        await signInWithEmailAndPassword(auth, ghostEmail, SYSTEM_MASTER_PASSWORD);
      } catch (authError: any) {
        // Fallback untuk akun lama yang didaftarkan sebelum sistem Master Password
        if (authError.code === 'auth/wrong-password' || authError.code === 'auth/invalid-credential') {
          const oldGhostPassword = `Salingaya+${cleanPhone}`;
          await signInWithEmailAndPassword(auth, ghostEmail, oldGhostPassword);
        } else {
          throw authError; // Lempar error lain ke catch utama
        }
      }

      // Jika berhasil, JANGAN redirect. Lanjut Tahap 2: Pengiriman OTP
      const otpCode = Math.floor(100000 + Math.random() * 900000).toString();
      const expiresAt = new Date().getTime() + 5 * 60 * 1000;

      await set(ref(db, `otp_sessions/${cleanPhone}`), {
        code: otpCode,
        expiresAt: expiresAt
      });

      const isSent = await sendOTPViaProvider(formattedPhone, otpCode);
      if (!isSent) {
        setIsLoading(false);
        return; 
      }

      setShowOtpInput(true);
      setCountdown(60);
    } catch (error: any) {
      console.error("[LOGIN] Phone Auth Error:", error);
      toast.error("Gagal masuk", { description: translateAuthError(error) });
    } finally {
      setIsLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!otp) return;
    setIsLoading(true);
    try {
      const formattedPhone = phone.startsWith('0') ? `+62${phone.slice(1)}` : (phone.startsWith('+') ? phone : `+62${phone}`);
      const cleanPhone = formattedPhone.replace(/\+/g, '');

      const otpRef = ref(db, `otp_sessions/${cleanPhone}`);
      const snapshot = await get(otpRef);

      if (!snapshot.exists()) {
        toast.error("Kode OTP tidak valid", { description: "Silakan minta kode baru." });
        setIsLoading(false);
        return;
      }

      const sessionData = snapshot.val();
      const now = new Date().getTime();

      // Tahap 3: Verifikasi OTP Lokal
      if (String(sessionData.code) !== String(otp) || now > sessionData.expiresAt) {
        toast.error("Kode OTP salah. Silakan periksa kembali WhatsApp Anda.");
        setIsLoading(false);
        return;
      }

      await remove(otpRef);

      // Verifikasi berhasil, redirect karena Firebase sudah authenticated di Tahap 1
      const currentUser = auth.currentUser;
      if (!currentUser) {
        throw new Error("Sesi login hilang.");
      }

      const dbRef = ref(db);
      const userSnapshot = await get(child(dbRef, `users/${currentUser.uid}`));

      let userRole = "Pembeli";
      if (userSnapshot.exists()) {
        userRole = userSnapshot.val().role || "Pembeli";
      }

      toast.success("Verifikasi berhasil!");
      redirectUser(userRole);
    } catch (error: any) {
      console.error("[LOGIN] Verify OTP Error:", error);
      toast.error("Terjadi kesalahan", { description: translateAuthError(error) });
    } finally {
      setIsLoading(false);
    }
  };

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) {
      toast.error("Mohon isi email dan password");
      return;
    }

    setIsLoading(true);
    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Check role
      const dbRef = ref(db);
      const snapshot = await get(child(dbRef, `users/${user.uid}`));
      let userRole = "Pembeli";
      if (snapshot.exists()) {
        userRole = snapshot.val().role || "Pembeli";
      }

      toast.success("Berhasil masuk!");
      redirectUser(userRole);
    } catch (error: any) {
      console.error(error);
      toast.error("Gagal masuk", { description: translateAuthError(error) });
    } finally {
      setIsLoading(false);
    }
  };

  // Validasi lokal pre-submit
  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isPasswordValid = password.length >= 6;
  const isPhoneValid = /^[0-9]{9,15}$/.test(phone);
  const isPhonePasswordValid = phonePassword.length >= 6;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <Navbar />
      <div className="flex-1 flex items-center justify-center py-16 px-4">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="w-full max-w-md bg-card rounded-2xl border border-border p-8 shadow-sm"
        >
          <h1 className="font-display text-2xl font-bold text-foreground text-center">Masuk</h1>
          <p className="text-sm text-muted-foreground text-center mt-2">Selamat datang kembali di Salin Gaya</p>

          <div className="flex gap-2 mb-6 bg-secondary p-1 rounded-xl mt-6">
            <button
              onClick={() => { setLoginMethod("email"); setShowOtpInput(false); }}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-colors ${loginMethod === "email" ? "bg-background shadow-sm text-foreground" : "text-muted-foreground hover:text-foreground"}`}
            >
              Email
            </button>
            <button
              onClick={() => setLoginMethod("phone")}
              className={`flex-1 py-2 text-sm font-medium rounded-lg transition-colors ${loginMethod === "phone" ? "bg-background shadow-sm text-foreground" : "text-muted-foreground hover:text-foreground"}`}
            >
              Nomor HP
            </button>
          </div>

          {loginMethod === "email" ? (
            <form className="mt-4 space-y-4" onSubmit={handleEmailLogin}>
              <div>
                <label className="text-sm font-medium text-foreground block mb-1.5">Email</label>
                <input
                  type="email"
                  placeholder="nama@email.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  disabled={isLoading}
                  className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary outline-none text-sm transition-all"
                />
              </div>
              <div>
                <label className="text-sm font-medium text-foreground block mb-1.5">Password</label>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={isLoading}
                  className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary outline-none text-sm transition-all"
                />
              </div>
              <div className="text-right">
                <Link to="/forgot-password" className="text-xs text-primary hover:underline bg-transparent border-none p-0 cursor-pointer inline-block">
                  Lupa password?
                </Link>
              </div>
              <button
                type="submit"
                disabled={isLoading || !isEmailValid || !isPasswordValid}
                className="w-full py-2.5 bg-primary text-primary-foreground font-medium rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50"
              >
                {isLoading ? "Memproses..." : "Masuk"}
              </button>
            </form>
          ) : (
            <form className="mt-4 space-y-4" onSubmit={showOtpInput ? handleVerifyOtp : handleSendOtp}>
              {!showOtpInput ? (
                <>
                  <div>
                    <label className="text-sm font-medium text-foreground block mb-1.5">Nomor Handphone</label>
                    <input
                      type="tel"
                      placeholder="081234567890"
                      value={phone}
                      onChange={(e) => setPhone(e.target.value.replace(/[^0-9]/g, ''))}
                      disabled={isLoading}
                      className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary outline-none text-sm transition-all"
                    />
                  </div>
                  <div>
                    <label className="text-sm font-medium text-foreground block mb-1.5">Password</label>
                    <input
                      type="password"
                      placeholder="••••••••"
                      value={phonePassword}
                      onChange={(e) => setPhonePassword(e.target.value)}
                      disabled={isLoading}
                      className="w-full px-4 py-2.5 rounded-lg border border-border bg-background text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary outline-none text-sm transition-all"
                    />
                  </div>
                  <div className="text-right">
                    <Link to="/forgot-password" className="text-xs text-primary hover:underline bg-transparent border-none p-0 cursor-pointer inline-block">
                      Lupa password?
                    </Link>
                  </div>
                </>
              ) : (
                <div className="space-y-3">
                  <div className="bg-secondary/50 p-4 rounded-lg border border-border flex items-center justify-between">
                    <div className="min-w-0">
                      <p className="text-xs text-muted-foreground">OTP dikirim ke</p>
                      <p className="font-medium text-sm text-foreground truncate">{phone}</p>
                    </div>
                    <button
                      type="button"
                      onClick={() => {
                        setShowOtpInput(false);
                        setOtp("");
                        setCountdown(0);
                      }}
                      disabled={isLoading}
                      className="text-xs text-primary hover:underline font-medium shrink-0 ml-2"
                    >
                      Ubah Nomor
                    </button>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-foreground block mb-1.5">Kode OTP (6 Digit)</label>
                    <input
                      type="text"
                      placeholder="Masukkan 6 angka OTP"
                      value={otp}
                      onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                      disabled={isLoading}
                      maxLength={6}
                      className="w-full px-4 py-3 rounded-lg border border-border bg-background text-foreground placeholder:text-muted-foreground focus:ring-2 focus:ring-primary outline-none text-xl tracking-[0.5em] text-center font-bold font-mono transition-all"
                    />
                  </div>
                </div>
              )}

              <button
                type="submit"
                disabled={isLoading || (showOtpInput ? otp.length !== 6 : (!isPhoneValid || !isPhonePasswordValid))}
                className="w-full py-2.5 bg-primary text-primary-foreground font-medium rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50"
              >
                {isLoading ? "Memproses..." : (showOtpInput ? "Verifikasi OTP" : "Masuk")}
              </button>

              {showOtpInput && (
                <div className="text-center pt-2">
                  {countdown > 0 ? (
                    <p className="text-sm text-muted-foreground">
                      Kirim ulang OTP dalam <span className="font-bold text-foreground">{countdown}s</span>
                    </p>
                  ) : (
                    <button
                      type="button"
                      onClick={handleSendOtp}
                      disabled={isLoading}
                      className="text-sm text-primary font-medium hover:underline"
                    >
                      Kirim Ulang OTP
                    </button>
                  )}
                </div>
              )}
            </form>
          )}

          <div className="mt-6 flex items-center gap-3">
            <div className="h-px flex-1 bg-border" />
            <span className="text-xs text-muted-foreground">atau</span>
            <div className="h-px flex-1 bg-border" />
          </div>

          <div className="mt-4 space-y-2">
            <button 
              onClick={() => handleSocialLogin(googleProvider)}
              disabled={isLoading}
              className="w-full py-2.5 border border-border rounded-lg text-sm font-medium text-foreground hover:bg-secondary transition-colors disabled:opacity-50"
            >
              Masuk dengan Google
            </button>
            <button 
              onClick={() => handleSocialLogin(facebookProvider)}
              disabled={isLoading}
              className="w-full py-2.5 border border-border rounded-lg text-sm font-medium text-foreground hover:bg-secondary transition-colors disabled:opacity-50"
            >
              Masuk dengan Facebook
            </button>
          </div>

          <p className="mt-6 text-center text-sm text-muted-foreground">
            Belum punya akun?{" "}
            <Link to="/register" className="text-primary font-medium hover:underline">Daftar</Link>
          </p>
        </motion.div>
      </div>

      {/* Role Selection Modal */}
      {showRoleModal && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-card w-full max-w-sm rounded-2xl p-6 shadow-xl border border-border"
          >
            <h3 className="text-xl font-bold text-center mb-2">Pilih Role Akun</h3>
            <p className="text-sm text-center text-muted-foreground mb-6">Apakah Anda ingin melanjutkan sebagai Pembeli atau Penjual?</p>

            <div className="space-y-3">
              <button 
                onClick={() => handleRoleSelection("Pembeli")}
                className="w-full py-3 bg-secondary text-secondary-foreground font-medium rounded-lg hover:bg-primary/10 hover:text-primary transition-colors border border-border"
              >
                Saya Pembeli
              </button>
              <button 
                onClick={() => handleRoleSelection("Penjual")}
                className="w-full py-3 bg-secondary text-secondary-foreground font-medium rounded-lg hover:bg-primary/10 hover:text-primary transition-colors border border-border"
              >
                Saya Penjual (Buka Toko)
              </button>
            </div>

            <button 
              onClick={() => {
                setShowRoleModal(false);
                setPendingUser(null);
                auth.signOut();
              }}
              className="w-full mt-4 py-2 text-sm text-muted-foreground hover:text-foreground transition-colors"
            >
              Batal
            </button>
          </motion.div>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from "react";
import { useAuth } from "@/frontend/contexts/AuthContext";
import Navbar from "@/frontend/components/layout/Navbar";
import Footer from "@/frontend/components/layout/Footer";
import { db } from "@/backend/config/firebase";
import { ref, onValue, query, orderByChild, equalTo } from "firebase/database";
import { Package, Clock, CheckCircle2, AlertCircle } from "lucide-react";
import { formatPrice, getValidImageUrl } from "@/lib/utils";

interface OrderItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  sellerUid?: string;
  images?: string[];
}

interface Order {
  id: string;
  buyerUid: string;
  items: OrderItem[];
  shippingCost: number;
  subtotal: number;
  totalAmount: number;
  status: string;
  createdAt: number | any;
  courier: string;
  shippingAddress: any;
}

export default function OrderHistory() {
  const { currentUser, role } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!currentUser) return;

    const ordersRef = ref(db, "orders");

    // Listen to all orders or query by buyer if buyer. 
    // Since Firebase RTDB queries are limited without proper indexes, we'll fetch and filter client-side for flexibility,
    // especially for Sellers who need to search deep within items.

    const unsubscribe = onValue(ordersRef, (snapshot) => {
      if (snapshot.exists()) {
        const data = snapshot.val();
        const allOrders: Order[] = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));

        let filteredOrders: Order[] = [];

        if (role === "Pembeli") {
          filteredOrders = allOrders.filter(order => order.buyerUid === currentUser.uid);
        } else if (role === "Penjual") {
          // Penjual only sees orders that contain at least one item they sell
          filteredOrders = allOrders.map(order => {
            const myItems = (order.items || []).filter(item => item.sellerUid === currentUser.uid);
            return { ...order, items: myItems };
          }).filter(order => order.items.length > 0);
        }

        // Sort by newest first
        filteredOrders.sort((a, b) => {
          const timeA = a.createdAt || 0;
          const timeB = b.createdAt || 0;
          return timeB - timeA;
        });

        setOrders(filteredOrders);
      } else {
        setOrders([]);
      }
      setIsLoading(false);
    }, (error) => {
      console.error("Error fetching orders:", error);
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, [currentUser, role]);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "UNPAID":
        return <span className="px-2.5 py-1 text-xs font-semibold rounded-full bg-yellow-100 text-yellow-800 flex items-center gap-1"><Clock className="w-3 h-3"/> Belum Dibayar</span>;
      case "PAID":
      case "PROCESSING":
        return <span className="px-2.5 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-800 flex items-center gap-1"><Package className="w-3 h-3"/> Sedang Diproses</span>;
      case "SHIPPED":
        return <span className="px-2.5 py-1 text-xs font-semibold rounded-full bg-purple-100 text-purple-800 flex items-center gap-1"><Package className="w-3 h-3"/> Dikirim</span>;
      case "COMPLETED":
        return <span className="px-2.5 py-1 text-xs font-semibold rounded-full bg-green-100 text-green-800 flex items-center gap-1"><CheckCircle2 className="w-3 h-3"/> Selesai</span>;
      default:
        return <span className="px-2.5 py-1 text-xs font-semibold rounded-full bg-gray-100 text-gray-800 flex items-center gap-1"><AlertCircle className="w-3 h-3"/> {status}</span>;
    }
  };

  return (
    <div className="min-h-screen bg-muted/30 flex flex-col">
      <Navbar />

      <main className="flex-1 container max-w-4xl mx-auto py-10 px-4">
        <div className="mb-8">
          <h1 className="text-3xl font-display font-bold text-foreground">
            {role === "Pembeli" ? "Pesanan Saya" : "Pesanan Masuk"}
          </h1>
          <p className="text-muted-foreground mt-2">
            {role === "Pembeli" ? "Lacak dan kelola riwayat pembelian Anda." : "Daftar barang yang harus Anda kirim ke pelanggan."}
          </p>
        </div>

        {isLoading ? (
          <div className="flex justify-center items-center py-20">
            <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full"></div>
          </div>
        ) : orders.length === 0 ? (
          <div className="bg-card rounded-2xl border border-border p-12 text-center shadow-sm">
            <Package className="w-16 h-16 text-muted-foreground/30 mx-auto mb-4" />
            <h3 className="text-xl font-bold text-foreground mb-2">Belum ada pesanan</h3>
            <p className="text-muted-foreground">
              {role === "Pembeli" ? "Anda belum melakukan transaksi apapun. Yuk mulai belanja!" : "Belum ada pelanggan yang membeli barang Anda."}
            </p>
          </div>
        ) : (
          <div className="space-y-6">
            {orders.map((order) => (
              <div key={order.id} className="bg-card rounded-xl border border-border overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                {/* Order Header */}
                <div className="border-b border-border bg-secondary/50 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                  <div>
                    <p className="text-xs text-muted-foreground mb-1">ID Pesanan: <span className="font-mono text-foreground">{order.id}</span></p>
                    <div className="flex items-center gap-3">
                      <span className="font-semibold text-sm">
                        {new Date(order.createdAt).toLocaleDateString('id-ID', { year: 'numeric', month: 'long', day: 'numeric' })}
                      </span>
                      {getStatusBadge(order.status)}
                    </div>
                  </div>
                  {role === "Pembeli" && order.status === "UNPAID" && (
                    <button className="px-4 py-2 bg-primary text-primary-foreground text-sm font-medium rounded-lg hover:opacity-90">
                      Bayar Sekarang
                    </button>
                  )}
                  {role === "Penjual" && order.status === "PAID" && (
                    <button className="px-4 py-2 bg-primary text-primary-foreground text-sm font-medium rounded-lg hover:opacity-90">
                      Proses & Kirim
                    </button>
                  )}
                </div>

                {/* Order Items */}
                <div className="p-6">
                  <div className="space-y-4">
                    {order.items.map((item, idx) => (
                      <div key={idx} className="flex gap-4">
                        <div className="w-20 h-20 rounded-lg bg-muted overflow-hidden shrink-0">
                          <img src={getValidImageUrl(item)} alt={item.name} className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1">
                          <h4 className="font-medium text-foreground">{item.name}</h4>
                          <p className="text-sm text-muted-foreground mt-1">{item.quantity} barang x {formatPrice(item.price)}</p>
                        </div>
                        <div className="text-right">
                          <p className="font-bold text-foreground">{formatPrice(item.price * item.quantity)}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Order Footer */}
                <div className="border-t border-border bg-secondary/30 px-6 py-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                  <div className="text-sm">
                    <p className="text-muted-foreground">Kurir: <span className="font-medium text-foreground">{order.courier}</span></p>
                    {role === "Penjual" && (
                      <p className="text-muted-foreground mt-1">Tujuan: <span className="font-medium text-foreground">{order.shippingAddress?.city || "-"}</span></p>
                    )}
                  </div>

                  {role === "Pembeli" ? (
                     <div className="text-right w-full sm:w-auto">
                       <p className="text-xs text-muted-foreground mb-1">Total Belanja</p>
                       <p className="text-xl font-bold text-primary">{formatPrice(order.totalAmount)}</p>
                     </div>
                  ) : (
                    <div className="text-right w-full sm:w-auto">
                      <p className="text-xs text-muted-foreground mb-1">Total Pendapatan (Item ini)</p>
                      <p className="text-xl font-bold text-primary">
                        {formatPrice(order.items.reduce((acc, curr) => acc + (curr.price * curr.quantity), 0))}
                      </p>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { Star, ShoppingCart, MessageCircle, Shield, ArrowLeft, Loader2, Send } from "lucide-react";
import { motion } from "framer-motion";
import Navbar from "@/frontend/components/layout/Navbar";
import Footer from "@/frontend/components/layout/Footer";
import { useCart } from "@/frontend/contexts/CartContext";
import { useAuth } from "@/frontend/contexts/AuthContext";
import { db } from "@/backend/config/firebase";
import { ref as dbRef, get, child, onValue, push, set, serverTimestamp } from "firebase/database";
import { toast } from "sonner";
import { RTDBProduct } from "@/frontend/components/layout/ProductCard";
import { formatPrice, getValidImageUrl } from "@/lib/utils";
import { products as localProducts } from "@/backend/types";
import { useChatContext } from "@/frontend/contexts/ChatContext";
import { sendMessage, getChatRoomId } from "@/backend/services/chatService";

interface Review {
  id: string;
  rating: number;
  comment: string;
  reviewerName: string;
  createdAt: number;
}

export default function ProductDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { currentUser, role } = useAuth();
  const { openChat } = useChatContext();

  const [product, setProduct] = useState<RTDBProduct | null>(null);
  const [sellerName, setSellerName] = useState("Penjual");
  const [isLoading, setIsLoading] = useState(true);

  // Review states
  const [reviews, setReviews] = useState<Review[]>([]);
  const [newRating, setNewRating] = useState(5);
  const [newComment, setNewComment] = useState("");
  const [isSubmittingReview, setIsSubmittingReview] = useState(false);

  useEffect(() => {
    if (!id) return;

    const fetchProduct = async () => {
      try {
        const snapshot = await get(child(dbRef(db), `products/${id}`));
        if (snapshot.exists()) {
          const data = snapshot.val();
          setProduct({ id, ...data });

          // Fetch seller name if sellerUid exists
          if (data.sellerUid) {
            const sellerSnap = await get(child(dbRef(db), `users/${data.sellerUid}`));
            if (sellerSnap.exists() && sellerSnap.val().name) {
              setSellerName(sellerSnap.val().name);
            }
          }
        } else {
          // Cek fallback data lokal jika produk tidak ada di Firebase (untuk mock data ID 1-8)
          // Gunakan String() untuk membandingkan agar kebal perbedaan tipe data (string vs number)
          const localProduct = localProducts.find(p => String(p.id) === String(id));
          if (localProduct) {
            setProduct(localProduct as any);
            setSellerName(localProduct.seller || "Salin Gaya");
          }
        }
      } catch (error) {
        console.error("Error fetching product:", error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchProduct();

    // Listen for reviews
    const reviewsRef = dbRef(db, `reviews/${id}`);
    const unsubscribe = onValue(reviewsRef, (snapshot) => {
      if (snapshot.exists()) {
        const data = snapshot.val();
        const loadedReviews: Review[] = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        loadedReviews.sort((a, b) => b.createdAt - a.createdAt);
        setReviews(loadedReviews);
      } else {
        setReviews([]);
      }
    });

    return () => unsubscribe();
  }, [id]);

  const handleAddToCart = () => {
    if (product) {
      addToCart(product);
      toast.success("Masuk Keranjang", { description: `${product.name} ditambahkan.` });
    }
  };

  const handleSubmitReview = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) {
      toast.error("Silakan login untuk memberikan ulasan");
      navigate("/login");
      return;
    }
    if (!newComment.trim()) {
      toast.error("Ulasan tidak boleh kosong");
      return;
    }
    if (!id) return;

    setIsSubmittingReview(true);
    try {
      const reviewRef = push(dbRef(db, `reviews/${id}`));
      await set(reviewRef, {
        rating: newRating,
        comment: newComment,
        reviewerName: currentUser.displayName || "Pengguna",
        createdAt: serverTimestamp()
      });

      toast.success("Ulasan berhasil dikirim");
      setNewComment("");
      setNewRating(5);
    } catch (error) {
      console.error("Failed to submit review", error);
      toast.error("Gagal mengirim ulasan");
    } finally {
      setIsSubmittingReview(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex flex-col">
        <Navbar />
        <div className="flex-1 flex items-center justify-center">
          <Loader2 className="w-8 h-8 animate-spin text-primary" />
        </div>
        <Footer />
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen bg-background flex flex-col">
        <Navbar />
        <div className="container mx-auto px-4 py-20 text-center flex-1">
          <p className="text-muted-foreground">Produk tidak ditemukan.</p>
          <Link to="/" className="text-primary hover:underline mt-4 inline-block">Kembali ke Home</Link>
        </div>
        <Footer />
      </div>
    );
  }

  const averageRating = reviews.length > 0 
    ? (reviews.reduce((acc, rev) => acc + rev.rating, 0) / reviews.length).toFixed(1)
    : 0;

  return (
    <div className="min-h-screen bg-background flex flex-col">
      <Navbar />
      <main className="flex-1 container mx-auto px-4 py-8 max-w-6xl">
        <Link to="/" className="inline-flex items-center gap-2 text-sm text-muted-foreground hover:text-primary transition-colors mb-6">
          <ArrowLeft className="w-4 h-4" /> Kembali ke Katalog
        </Link>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12 mb-16">
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="aspect-square rounded-xl overflow-hidden bg-muted border border-border"
          >
            <img 
              src={getValidImageUrl(product)} 
              alt={product.name} 
              className="w-full h-full object-cover" 
            />
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.1 }}
            className="flex flex-col"
          >
            <div>
              {product.aiEligibilityScore === "LAYAK" && (
                <span className="inline-block bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 text-xs font-bold px-3 py-1 rounded-full mb-3 uppercase">
                  Verified by AI
                </span>
              )}
              <h1 className="font-display text-2xl md:text-3xl font-bold text-foreground mb-2">{product.name}</h1>

              <div className="flex items-center gap-2 mt-2">
                <div className="flex items-center gap-1">
                  {Array.from({ length: 5 }).map((_, i) => (
                    <Star 
                      key={i} 
                      className={`w-4 h-4 ${i < Math.floor(Number(averageRating)) ? "fill-orange-400 text-orange-400" : "text-border"}`} 
                    />
                  ))}
                </div>
                <span className="text-sm font-medium text-foreground">{averageRating}</span>
                <span className="text-sm text-muted-foreground">({reviews.length} ulasan)</span>
              </div>

              <div className="mt-6 flex items-baseline gap-3">
                <span className="text-3xl font-bold text-primary">{formatPrice(product.price)}</span>
              </div>

              <div className="mt-8">
                <h3 className="font-medium text-foreground mb-2">Deskripsi Produk</h3>
                <p className="text-muted-foreground leading-relaxed text-sm whitespace-pre-wrap">{product.description}</p>
              </div>

              <div className="mt-6 p-4 bg-secondary/50 rounded-lg border border-border">
                <p className="text-sm text-muted-foreground">
                  Dijual oleh: <span className="font-bold text-foreground">{sellerName}</span>
                </p>
              </div>
            </div>

            <div className="mt-auto pt-8 flex gap-3">
              <button
                onClick={handleAddToCart}
                className="flex-1 py-3 bg-primary text-primary-foreground font-medium rounded-xl hover:opacity-90 transition-opacity flex items-center justify-center gap-2"
              >
                <ShoppingCart className="w-5 h-5" /> Masukkan Keranjang
              </button>
              <button 
                onClick={(e) => {
                  e.preventDefault();
                  if (!currentUser) {
                    toast.error("Akses Ditolak", { description: "Silakan login terlebih dahulu untuk mulai chat." });
                    navigate("/login");
                    return;
                  }
                  if (role === "Penjual") {
                    toast.error("Akses Ditolak", { description: "Akun Penjual tidak dapat melakukan chat/pembelian." });
                    return;
                  }
                  const sellerId = product.sellerUid || "unknown_seller";
                  const imageUrl = getValidImageUrl(product);
                  openChat(currentUser.uid, sellerId, product.id, product.name, imageUrl, product.price);

                  const roomId = getChatRoomId(currentUser.uid, sellerId, product.id);
                  sendMessage(roomId, currentUser.uid, currentUser.displayName || "Pembeli", `Halo, apakah ${product.name} masih tersedia?`);
                }}
                className="px-6 py-3 border border-border text-foreground font-medium rounded-xl hover:bg-secondary transition-colors flex items-center gap-2 cursor-pointer"
              >
                <MessageCircle className="w-5 h-5" /> Chat
              </button>
            </div>

            <div className="mt-6 p-4 bg-card rounded-lg border border-border flex items-start gap-3">
              <Shield className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
              <div>
                <p className="text-sm font-medium text-foreground">Transaksi Aman</p>
                <p className="text-xs text-muted-foreground mt-1">
                  Pembayaran dilindungi oleh sistem escrow. Dana diteruskan ke penjual setelah barang Anda terima.
                </p>
              </div>
            </div>
          </motion.div>
        </div>

        {/* REVIEWS SECTION */}
        <div className="border-t border-border pt-10">
          <h2 className="text-2xl font-bold text-foreground mb-6">Ulasan Pembeli</h2>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

            {/* Review Form */}
            <div className="md:col-span-1 bg-card border border-border p-6 rounded-xl h-fit">
              <h3 className="font-bold text-lg mb-4">Tulis Ulasan</h3>
              <form onSubmit={handleSubmitReview} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Rating</label>
                  <div className="flex gap-1">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button 
                        key={star}
                        type="button"
                        onClick={() => setNewRating(star)}
                        className="focus:outline-none"
                      >
                        <Star className={`w-8 h-8 ${star <= newRating ? 'fill-orange-400 text-orange-400' : 'text-border'} hover:scale-110 transition-transform`} />
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">Ulasan Anda</label>
                  <textarea 
                    rows={4}
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                    placeholder="Bagaimana kualitas barang ini?"
                    className="w-full px-3 py-2 border border-border rounded-lg bg-background text-sm resize-none focus:ring-2 focus:ring-primary outline-none"
                  />
                </div>
                <button 
                  type="submit"
                  disabled={isSubmittingReview || !newComment.trim()}
                  className="w-full py-2.5 bg-primary text-primary-foreground font-medium rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50 flex items-center justify-center gap-2"
                >
                  {isSubmittingReview ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                  Kirim Ulasan
                </button>
              </form>
            </div>

            {/* Reviews List */}
            <div className="md:col-span-2 space-y-4">
              {reviews.length === 0 ? (
                <div className="p-8 text-center bg-secondary/30 rounded-xl border border-border border-dashed">
                  <p className="text-muted-foreground">Belum ada ulasan untuk produk ini. Jadilah yang pertama!</p>
                </div>
              ) : (
                reviews.map((review) => (
                  <div key={review.id} className="p-5 bg-card border border-border rounded-xl">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-secondary rounded-full flex items-center justify-center font-bold text-muted-foreground uppercase">
                          {review.reviewerName.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-sm text-foreground">{review.reviewerName}</p>
                          <div className="flex gap-0.5 mt-0.5">
                            {Array.from({ length: 5 }).map((_, i) => (
                              <Star key={i} className={`w-3 h-3 ${i < review.rating ? "fill-orange-400 text-orange-400" : "text-border"}`} />
                            ))}
                          </div>
                        </div>
                      </div>
                      <span className="text-xs text-muted-foreground">
                        {review.createdAt ? new Date(review.createdAt).toLocaleDateString('id-ID') : 'Baru saja'}
                      </span>
                    </div>
                    <p className="text-sm text-foreground mt-3 leading-relaxed">{review.comment}</p>
                  </div>
                ))
              )}
            </div>

          </div>
        </div>

      </main>
      <Footer />
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/frontend/contexts/AuthContext";
import Navbar from "@/frontend/components/layout/Navbar";
import Footer from "@/frontend/components/layout/Footer";
import { auth, db, storage } from "@/backend/config/firebase";
import { updateProfile, deleteUser } from "firebase/auth";
import { ref as dbRef, update, get, child, remove } from "firebase/database";
import { ref as storageRef, uploadBytes, getDownloadURL } from "firebase/storage";
import { toast } from "sonner";
import { User, Camera, Trash2, Loader2, Save, MapPin, Shield, Map } from "lucide-react";
import UpdateEmailForm from "@/frontend/components/profile/UpdateEmailForm";
import UpdatePasswordForm from "@/frontend/components/profile/UpdatePasswordForm";
import { motion, AnimatePresence } from "framer-motion";

export default function ProfilePage() {
  const { currentUser, role } = useAuth();
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState<"biodata" | "alamat" | "keamanan">("biodata");

  const [name, setName] = useState("");
  const [dbEmail, setDbEmail] = useState("");
  const [dbPhone, setDbPhone] = useState("");
  const [photoURL, setPhotoURL] = useState("");
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [street, setStreet] = useState("");
  const [city, setCity] = useState("");
  const [province, setProvince] = useState("");

  useEffect(() => {
    if (!currentUser) {
      navigate("/login");
      return;
    }

    setName(currentUser.displayName || "");

    // Ambil data tambahan dari RTDB
    const fetchUserData = async () => {
      try {
        const snapshot = await get(child(dbRef(db), `users/${currentUser.uid}`));
        if (snapshot.exists()) {
          const data = snapshot.val();
          if (data.name && !currentUser.displayName) setName(data.name);
          if (data.email) setDbEmail(data.email);
          if (data.phone) setDbPhone(data.phone);
          if (data.photoURL) setPhotoURL(data.photoURL);
          if (data.address) {
            setStreet(data.address.street || "");
            setCity(data.address.city || "");
            setProvince(data.address.province || "");
          }
        } else {
          setDbEmail(currentUser.email || "");
        }
      } catch (e) {
        console.error("Failed to fetch user data:", e);
        setDbEmail(currentUser.email || "");
      }
    };

    fetchUserData();
  }, [currentUser, navigate]);

  useEffect(() => {
    return () => {
      if (previewImage) URL.revokeObjectURL(previewImage);
    };
  }, [previewImage]);

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!['image/jpeg', 'image/png'].includes(file.type) && !file.name.match(/\.(jpg|jpeg|png)$/i)) {
      toast.error("Format file tidak didukung", { description: "Harap unggah file JPG atau PNG." });
      return;
    }

    if (file.size > 10 * 1024 * 1024) {
      toast.error("Ukuran gambar terlalu besar", { description: "Maksimal 10 MB." });
      return;
    }

    const previewUrl = URL.createObjectURL(file);
    setPreviewImage(previewUrl);
    setSelectedFile(file);
  };

  const handleSaveProfile = async () => {
    if (!currentUser || !name.trim()) return;

    setIsUpdating(true);
    try {
      let currentPhotoURL = photoURL;

      if (selectedFile) {
        const avatarRef = storageRef(storage, `users/profile_pictures/${currentUser.uid}`);
        const snapshot = await uploadBytes(avatarRef, selectedFile);
        currentPhotoURL = await getDownloadURL(snapshot.ref);
        setPhotoURL(currentPhotoURL);
      }

      await updateProfile(currentUser, { 
        displayName: name,
        ...(selectedFile && { photoURL: currentPhotoURL })
      });

      await update(dbRef(db, `users/${currentUser.uid}`), {
        name: name,
        ...(selectedFile && { photoURL: currentPhotoURL }),
        address: {
          street: street,
          city: city,
          province: province
        }
      });

      setSelectedFile(null);
      setPreviewImage(null);
      toast.success("Profil berhasil disimpan!");
    } catch (error: any) {
      console.error(error);
      toast.error("Gagal menyimpan", { description: error.message });
    } finally {
      setIsUpdating(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (!currentUser) return;

    const confirmDelete = window.confirm(
      "Apakah Anda yakin ingin MENGHAPUS AKUN ini secara permanen? Semua data Anda akan hilang dan tindakan ini tidak dapat dibatalkan."
    );

    if (!confirmDelete) return;

    setIsDeleting(true);
    try {
      await remove(dbRef(db, `users/${currentUser.uid}`));
      await deleteUser(currentUser);

      toast.success("Akun telah dihapus.");
      navigate("/");
    } catch (error: any) {
      console.error(error);
      if (error.code === 'auth/requires-recent-login') {
        toast.error("Gagal menghapus", { description: "Tindakan ini sensitif. Silakan keluar dan masuk kembali sebelum mencoba menghapus akun." });
      } else {
        toast.error("Gagal menghapus akun", { description: error.message });
      }
      setIsDeleting(false);
    }
  };

  if (!currentUser) return null;

  // Masked Phone helper
  const formatMaskedPhone = (phone: string) => {
    if (!phone || phone.length < 5) return phone;
    const firstTwo = phone.substring(0, 4);
    const lastTwo = phone.substring(phone.length - 2);
    const masked = '*'.repeat(phone.length - 6);
    return `${firstTwo}${masked}${lastTwo}`;
  };

  const displayEmail = dbEmail || currentUser.email || "";
  const displayPhone = formatMaskedPhone(dbPhone) || "Belum ditambahkan";

  return (
    <div className="min-h-screen bg-muted/30 flex flex-col">
      <Navbar />

      <main className="flex-1 container max-w-5xl mx-auto py-10 px-4">
        <div className="flex flex-col md:flex-row gap-8">

          {/* Sidebar Menu */}
          <div className="w-full md:w-64 shrink-0">
            <div className="bg-card border border-border rounded-xl shadow-sm p-4 sticky top-24">
              <div className="mb-6 px-2 flex items-center gap-3">
                <div className="w-12 h-12 rounded-full bg-secondary overflow-hidden border border-border aspect-square">
                  {previewImage || photoURL ? (
                    <img src={previewImage || photoURL} alt="Avatar" className="w-full h-full object-cover" />
                  ) : (
                    <User className="w-full h-full p-2 text-muted-foreground" />
                  )}
                </div>
                <div className="overflow-hidden">
                  <p className="font-bold text-sm truncate">{name || "Pengguna"}</p>
                  <p className="text-xs text-muted-foreground truncate" title={displayEmail}>{displayEmail}</p>
                </div>
              </div>

              <nav className="space-y-1">
                <button
                  onClick={() => setActiveTab("biodata")}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${activeTab === "biodata" ? "bg-primary/10 text-primary" : "text-muted-foreground hover:bg-secondary hover:text-foreground"}`}
                >
                  <User className="w-4 h-4" />
                  Biodata Diri
                </button>
                <button
                  onClick={() => setActiveTab("alamat")}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${activeTab === "alamat" ? "bg-primary/10 text-primary" : "text-muted-foreground hover:bg-secondary hover:text-foreground"}`}
                >
                  <MapPin className="w-4 h-4" />
                  Alamat Pengiriman
                </button>
                <button
                  onClick={() => setActiveTab("keamanan")}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${activeTab === "keamanan" ? "bg-primary/10 text-primary" : "text-muted-foreground hover:bg-secondary hover:text-foreground"}`}
                >
                  <Shield className="w-4 h-4" />
                  Keamanan Akun
                </button>
              </nav>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 min-w-0">
            <AnimatePresence mode="wait">
              {activeTab === "biodata" && (
                <motion.div
                  key="biodata"
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.2 }}
                  className="bg-card border border-border rounded-xl shadow-sm p-6 sm:p-8"
